import {
  expect,
  Page,
  PageAssertionsToHaveScreenshotOptions,
  test,
} from '@playwright/test';

test.describe('public', () => {
  test('/auth/recover-callback', async ({ page }) => {
    await page.goto('/auth/recover-callback');
    await expect(page).toHaveScreenshot();
  });

  test('/auth/recover', async ({ page }) => {
    await page.goto('/auth/recover');
    await expect(page).toHaveScreenshot();
  });

  test('/auth/reset-password', async ({ page }) => {
    await page.goto('/auth/reset-password');
    await expect(page).toHaveScreenshot();
  });

  test('/auth/signin', async ({ page }) => {
    await page.goto('/auth/signin');
    await expect(page).toHaveScreenshot();
  });

  test('/auth/signup', async ({ page }) => {
    await page.goto('/auth/signup');
    await expect(page).toHaveScreenshot();
  });
});

function consoleScreenShotOptions(
  page: Page,
): PageAssertionsToHaveScreenshotOptions {
  return {
    fullPage: true,
    mask: [page.locator('.develop')],
  };
}

test.describe('super_admin', () => {
  test.use({ storageState: 'playwright/.auth/super_admin.json' });

  test('/super-admin/teams', async ({ page }) => {
    await page.goto('/super-admin/teams');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    // TeamCreationModal
    await page
      .getByRole('button', { name: 'Create New Team' })
      .click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'CANCEL' }).click();

    // CurrentTeamPlan
    await page
      .getByRole('table')
      .getByRole('row')
      .getByRole('button')
      .first()
      .click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page)); // SS of Menu
    await page.getByRole('menuitem', { name: 'Current' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // NextTeamPlan
    await page
      .getByRole('table')
      .getByRole('row')
      .getByRole('button')
      .first()
      .click();
    await page.getByRole('menuitem', { name: 'Next' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
    await page.getByRole('button', { name: 'DISCARD' }).click();

    // Plan Details
    await page
      .getByRole('table')
      .getByRole('row')
      .getByRole('button')
      .first()
      .click();
    await page.getByRole('menuitem', { name: 'Details' }).click();
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });

  test('/super-admin/notifications', async ({ page }) => {
    await page.goto('/super-admin/notifications');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));

    // NotificationCreationPage
    await page.goto('/super-admin/notifications/new');
    await expect(page).toHaveScreenshot(consoleScreenShotOptions(page));
  });
});

